 637 |                 function findSentenceRange(rootDoc, startNode, startOffset, pageBoundary) {
 638 |                     const sentenceEndRegex = /[.!?]/;
 639 |                     
 640 |                     // Helper: TreeWalker for linear text traversal within the page
 641 |                     function createWalker(root) {
 642 |                         return rootDoc.createTreeWalker(root, NodeFilter.SHOW_TEXT, null, false);
 643 |                     }
 644 | 
 645 |                     // 1. BACKWARD SCAN (Find start)
 646 |                     let currentStartNode = startNode;
 647 |                     let currentStartOffset = startOffset;
 648 |                     let finalStartNode = startNode;
 649 |                     let finalStartOffset = 0;
 650 | 
 651 |                     let textBefore = currentStartNode.textContent.substring(0, currentStartOffset);
 652 |                     let lastPuncIndex = -1;
 653 |                     for(let i = textBefore.length - 1; i >= 0; i--) {
 654 |                         if(sentenceEndRegex.test(textBefore[i])) { lastPuncIndex = i; break; }
 655 |                     }
 656 | 
 657 |                     if (lastPuncIndex !== -1) {
 658 |                         finalStartOffset = lastPuncIndex + 1;
 659 |                         if(currentStartNode.textContent[finalStartOffset] === ' ') finalStartOffset++;
 660 |                     } else {
 661 |                         const walker = createWalker(pageBoundary);
 662 |                         walker.currentNode = currentStartNode;
 663 |                         let prevNode = walker.previousNode();
 664 |                         let foundStart = false;
 665 | 
 666 |                         while (prevNode && !foundStart) {
 667 |                             const text = prevNode.textContent;
 668 |                             for (let i = text.length - 1; i >= 0; i--) {
 669 |                                 if (sentenceEndRegex.test(text[i])) {
 670 |                                     finalStartNode = prevNode; finalStartOffset = i + 1;
 671 |                                     if(text[finalStartOffset] === ' ') finalStartOffset++;
 672 |                                     foundStart = true; break;
 673 |                                 }
 674 |                             }
 675 |                             if (!foundStart) {
 676 |                                 finalStartNode = prevNode; finalStartOffset = 0;
 677 |                                 prevNode = walker.previousNode();
 678 |                             }
 679 |                         }
 680 |                     }
 681 | 
 682 |                     // 2. FORWARD SCAN (Find end)
 683 |                     let currentEndNode = startNode;
 684 |                     let currentEndOffset = startOffset;
 685 |                     let finalEndNode = startNode;
 686 |                     let finalEndOffset = startNode.textContent.length;
 687 | 
 688 |                     let textAfter = currentEndNode.textContent.substring(currentEndOffset);
 689 |                     let nextPuncIndex = textAfter.search(sentenceEndRegex);
 690 | 
 691 |                     if (nextPuncIndex !== -1) {
 692 |                         finalEndOffset = currentEndOffset + nextPuncIndex + 1;
 693 |                     } else {
 694 |                         const walker = createWalker(pageBoundary);
 695 |                         walker.currentNode = currentEndNode;
 696 |                         let nextNode = walker.nextNode();
 697 |                         let foundEnd = false;
