 699 |                         while (nextNode && !foundEnd) {
 700 |                             const text = nextNode.textContent;
 701 |                             const puncIdx = text.search(sentenceEndRegex);
 702 |                             if (puncIdx !== -1) {
 703 |                                 finalEndNode = nextNode; finalEndOffset = puncIdx + 1;
 704 |                                 foundEnd = true;
 705 |                             } else {
 706 |                                 finalEndNode = nextNode; finalEndOffset = text.length;
 707 |                                 nextNode = walker.nextNode();
 708 |                             }
 709 |                         }
 710 |                     }
