 712 |                     // Create the final Range
 713 |                     const r = rootDoc.createRange();
 714 |                     try {
 715 |                         r.setStart(finalStartNode, finalStartOffset);
 716 |                         r.setEnd(finalEndNode, finalEndOffset);
 717 |                         return r;
 718 |                     } catch (e) {
 719 |                         console.warn("Sentence Range Error:", e);
 720 |                         return null;
 721 |                     }
 722 |                 }
 723 |             } catch (err) {
