        if (e.data?.type === 'BOOK_READY') {
            const factor = window.innerWidth / 909;
            setScaleFactor(factor);
            setBookHeight(e.data.height);
        }

        // NEW: Pinch-to-Zoom Bridge
        if (e.data?.type === 'IFRAME_TOUCH') {
            const { touches, touchType } = e.data;
            if (touchType === 'touchstart' && touches.length === 2) {
                lastPinchDist.current = Math.hypot(touches[0].clientX - touches[1].clientX, touches[0].clientY - touches[1].clientY);
            } else if (touchType === 'touchmove' && touches.length === 2) {
                const dist = Math.hypot(touches[0].clientX - touches[1].clientX, touches[0].clientY - touches[1].clientY);
                if (lastPinchDist.current > 0) {
                    const delta = dist / lastPinchDist.current;
                    // Smoother zoom multiplier
                    const sensitivity = 0.5;
                    const newScale = scaleFactor * (1 + (delta - 1) * sensitivity);
                    setScaleFactor(Math.max(0.3, Math.min(newScale, 3.0)));
                }
                lastPinchDist.current = dist;
            } else if (touchType === 'touchend') {
                lastPinchDist.current = 0;
            }
        }

        // 1. Text Selection / Sentence Selection Bridge
        if (e.data?.type === 'TEXT_SELECT' || e.data?.type === 'SENTENCE_SELECTED') {
            const { text, rect } = e.data;
            setContextMenu({
                x: rect.x + (rect.width / 2),
                y: rect.y - (70 / scaleFactor),
                text: text
            });
        }

        if (e.data?.type === 'TEXT_DESELECT') {
            if (!isDraggingCtxRef.current) setContextMenu(null);
